arguments.command:
$ErrorActionPreference='Stop'
$root = (Get-Location).Path
$files = @(
  'agent-packs\issue-triage\.github\agents\triage-agent.agent.md',
  'agent-packs\issue-triage\.github\agents\related-issue-searcher.agent.md',
  'agent-packs\issue-triage\README.md',
  '.copilot-factory\sessions\2026-04-28-a1b2c3d4\artifacts\build-manifest.json'
)
foreach ($f in $files) { if (!(Test-Path -LiteralPath $f)) { throw "Missing $f" } }
$triage = Get-Content -LiteralPath $files[0] -Raw
$related = Get-Content -LiteralPath $files[1] -Raw
$readme = Get-Content -LiteralPath $files[2] -Raw
$manifest = Get-Content -LiteralPath $files[3] -Raw | ConvertFrom-Json
if ($triage -notmatch '^---\r?\nname: Issue Triage Agent\r?\ndescription: "Triages GitHub issues by suggesting labels, priority, and related or duplicate issues\. Use when given an issue URL or issue number for issue triage\. Triggers on: issue triage, triage issue, labels, priority, duplicate issue\."\r?\ntools: \["read", "search", "execute", "agent"\]\r?\n---') { throw 'Triage frontmatter mismatch' }
if ($related -notmatch '^---\r?\nname: Related Issue Searcher\r?\ndescription: "Searches GitHub issues and prior discussion for duplicates or related reports\. Called by Issue Triage Agent during issue triage\. Not for direct use\. Triggers on: related issues, duplicate issues, prior discussion\."\r?\ntools: \["read", "search", "execute"\]\r?\ndisable-model-invocation: true\r?\n---') { throw 'Related frontmatter mismatch' }
foreach ($content in @($triage,$related)) {
  if ($content -notmatch '## File Access Boundaries') { throw 'Missing File Access Boundaries' }
  if ($content -notmatch '\| \*\*Read\*\* \|') { throw 'Missing read boundary row' }
  if ($content -notmatch '\| \*\*Write\*\* \|') { throw 'Missing write boundary row' }
  if ($content -notmatch '\*\*Do NOT write to\*\*:') { throw 'Missing Do NOT write line' }
  if ($content.Length -ge 30000) { throw 'Prompt too long' }
}
if ($related -notmatch '## Invocation Guard') { throw 'Missing invocation guard' }
if ($readme -notmatch '@triage-agent <issue-url-or-number>') { throw 'README missing requested usage example' }
if ($manifest.files_created.Count -ne 4) { throw 'Manifest file count mismatch' }
foreach ($entry in $manifest.files_created) { if (!(Test-Path -LiteralPath $entry.relative_path)) { throw "Manifest path missing: $($entry.relative_path)" } }
Write-Output 'Verification passed.'
Write-Output "Files:"
$files | ForEach-Object { Write-Output "- $_" }
Write-Output "Prompt chars: triage=$($triage.Length); related=$($related.Length)"
